import React, { useState, useEffect } from 'react';
import { fetchUserOrderHistory } from '../utils/api';

function OrderHistory({ user }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (user && (user.name || user.username)) {
      fetchUserOrderHistory(user.name || user.username)
        .then(data => { if (Array.isArray(data)) setOrders(data); })
        .catch(err => console.error(err))
        .finally(() => setLoading(false));
    }
  }, [user]);

  if (!user) return <p style={{ padding: "30px", textAlign: "center" }}>Please log in to view your order receipt tracking history ledger.</p>;
  if (loading) return <p style={{ padding: "30px", textAlign: "center" }}>Scanning purchase ledger data arrays...</p>;

  return (
    <div style={{ padding: "30px", maxWidth: "900px", margin: "auto", fontFamily: "sans-serif" }}>
      <h3>📦 Your Order Purchase Tracking History</h3>
      {orders.length === 0 ? (
        <p style={{ color: "#666" }}>No historical order invoice records map detected for this profile signature yet.</p>
      ) : (
        orders.map(order => (
          <div key={order.orderId} style={{ border: "1px solid #ddd", borderRadius: "8px", padding: "20px", marginBottom: "20px", backgroundColor: "#fff", boxShadow: "0 2px 5px rgba(0,0,0,0.02)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", background: "#f8f9fa", padding: "10px", borderRadius: "4px", marginBottom: "15px" }}>
              <span><strong>Invoice ID:</strong> {order.orderId}</span>
              <span style={{ color: "#007bff", fontWeight: "bold" }}>🚚 {order.status}</span>
            </div>
            <p style={{ fontSize: "13px", color: "#666" }}>Purchased on: {new Date(order.timestamp).toLocaleString()}</p>
            
            <div style={{ margin: "10px 0" }}>
              {order.items.map((item, idx) => (
                <p key={idx} style={{ margin: "4px 0", fontSize: "14px" }}>
                  • {item.name} <span style={{ color: "#777" }}>x{item.quantity}</span> — ${item.price} each
                </p>
              ))}
            </div>
            <hr style={{ border: "none", borderTop: "1px dashed #eee" }} />
            <div style={{ textAlign: "right", fontWeight: "bold", fontSize: "16px", color: "#28a745" }}>
              Total Paid Amount: ${order.totalPaid.toFixed(2)}
            </div>
          </div>
        ))
      )}
    </div>
  );
}

export default OrderHistory;
